    /**
     * Detects charset from Byte Order Mark (BOM) in the byte buffer.
     * @param byteData the byte buffer to check for BOM
     * @return detected charset name, or null if no BOM found
     */
    private static String detectCharsetByBom(ByteBuffer byteData) {
        if (byteData.remaining() < 4) { // need at least 4 bytes to check for 32-bit BOMs
            // Check for 3-byte UTF-8 BOM if we have at least 3 bytes
            if (byteData.remaining() >= 3) {
                if (byteData.get(0) == (byte) 0xEF && 
                    byteData.get(1) == (byte) 0xBB && 
                    byteData.get(2) == (byte) 0xBF) {
                    return "UTF-8";
                }
            }
            // Check for 2-byte BOMs if we have at least 2 bytes
            if (byteData.remaining() >= 2) {
                if (byteData.get(0) == (byte) 0xFE && byteData.get(1) == (byte) 0xFF) {
                    return "UTF-16BE";
                } else if (byteData.get(0) == (byte) 0xFF && byteData.get(1) == (byte) 0xFE) {
                    return "UTF-16LE";
                }
            }
            return null; // Not enough bytes for 32-bit BOMs
        }

        // Check for 4-byte BOMs first (UTF-32)
        byte b0 = byteData.get(0);
        byte b1 = byteData.get(1);
        byte b2 = byteData.get(2);
        byte b3 = byteData.get(3);

        if (b0 == 0 && b1 == 0 && b2 == (byte) 0xFE && b3 == (byte) 0xFF) {
            return "UTF-32BE";
        } else if (b0 == (byte) 0xFF && b1 == (byte) 0xFE && b2 == 0 && b3 == 0) {
            return "UTF-32LE";
        }

        // Check for 3-byte UTF-8 BOM
        if (b0 == (byte) 0xEF && b1 == (byte) 0xBB && b2 == (byte) 0xBF) {
            return "UTF-8";
        }

        // Check for 2-byte UTF-16 BOMs
        if (b0 == (byte) 0xFE && b1 == (byte) 0xFF) {
            return "UTF-16BE";
        } else if (b0 == (byte) 0xFF && b1 == (byte) 0xFE) {
            return "UTF-16LE";
        }

        return null; // No known BOM found
    }
}

